<template>
  <div class="my-popups">
    <loader :is-visible="isLoading"></loader>

    <div class="modal d-block">
      <div class="modal-dialog modal-dialog-centered">
        <div class="modal-content">

          <div class="modal-header theme-primary partition-full d-flex">
            <h4 class="modal-title">{{ $t('Set Dates') }}</h4>
            <button type="button" class="close" @click="Close">
              <em class="fa fa-times"></em>
            </button>
          </div>

          <div class="modal-body">
            <dynamic-form
              lang="en"
              ref="ResourceRate"
              :buttons="buttons"
              :schema="FormSchema"
              :mandatorytext="MandatoryString"
              @OnSubmit="onSubmit">
            </dynamic-form>
          </div>

        </div>
      </div>
    </div>
  </div>
</template>

<script>
import DataService from "../../../services/DataService";

export default {
  props: {
    EditData: {
      type: Array,
      required: false,
      default: () => []
    }
  },

  data() {
    return {
      isLoading: false,
      MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',

      FormSchema: [
        {
          layoutType: "double",
          Data: [
            {
              astype: "DateField",
              label: this.$t('Start Date (M/D/YYYY)'),
              name: "StartDate",
              value: "",
              placeholder: this.$t('Start Date (M/D/YYYY)'),
              config: { format: "MM/DD/YYYY" },
              validationRules: { required: true },
              disabled: false
            },
            {
              astype: "DateField",
              label: this.$t('End Date (M/D/YYYY)'),
              name: "EndDate",
              value: "",
              placeholder: this.$t('End Date (M/D/YYYY)'),
              config: { format: "MM/DD/YYYY" },
              validationRules: { required: true },
              disabled: false
            }
          ]
        }
      ],

      buttons: [
        {
          type: "submit",
          class: "btn btn-success",
          text: "<i class='fa fa-save pr-2'></i>Set New Dates"
        }
      ]
    };
  },


watch: {
  EditData: {
    immediate: true,
    deep: true,
    handler(val) {
        debugger
      if (!val) return;

      this.FormSchema[0].Data[0].value =
        val.START_DATE ? new Date(val.START_DATE) : "";

      this.FormSchema[0].Data[1].value =
        val.END_DATE ? new Date(val.END_DATE) : "";
    }
  }
},

  methods: {
    async onSubmit(formfields) {
        debugger
      const vm = this;

      const isValid = await vm.$refs.ResourceRate.validateForm.validate();
      if (!isValid) return;

      const objData = {
        StartDate: formfields.StartDate
          ? new Date(formfields.StartDate).toISOString()
          : null,

        EndDate: formfields.EndDate
          ? new Date(formfields.EndDate).toISOString()
          : null
      };

      DataService.BulkUpdateRate(objData).then(response => {
        if (!response.data) return;

        const Result = JSON.parse(response.data)[0];
        if (parseInt(Result.RESULT) === 1) {
          vm.ShowAlert(
            vm.$t('AddedSuccess', [vm.$t('RateSchedule')]),
            "success",
            true,
            vm.$t("Alert")
          );
          vm.Close();
        } else {
          vm.ShowAlert(vm.$t("UnknownError"), "failure", vm.$t('Alert'));
        }
      });
    },

    Close() {
      this.$parent.FetchData();
      this.$parent.isSetDate = false;
    }
  }
};
</script>
